import {waitForPiko} from '../../../shared/utils';
import {createFormStateManager, type FormStateManager} from '@/services/FormStateManager';
import type {HookManagerLike} from '@/coreServices';

/** Services injected by the core shim. */
export interface FormsCoreServices {
    /** Hook manager for emitting form state events. */
    hookManager: HookManagerLike;
}

/** Public API registered with the core shim. */
export interface FormsCapabilityAPI {
    /** Creates a FormStateManager for tracking form dirty state. */
    createFormStateManager(deps: { hookManager: HookManagerLike }): FormStateManager;
}

/** Factory signature expected by PPFramework. */
export type FormsCapabilityFactory = (services: FormsCoreServices) => FormsCapabilityAPI;

/**
 * Creates the forms capability from core services.
 *
 * @param _services - Core services provided by the shim.
 * @returns The forms capability API.
 */
function createFormsCapability(_services: FormsCoreServices): FormsCapabilityAPI {
    return {
        createFormStateManager(deps) {
            return createFormStateManager(deps);
        },
    };
}

waitForPiko('forms')
    .then((pk) => {
        pk._registerCapability('forms', createFormsCapability);
    })
    .catch((err: unknown) => {
        console.error('[piko/forms] Failed to initialise:', err);
    });
